import{_ as e,o as t,c as r,ag as l}from"./chunks/framework.DXGyWiRo.js";const o="/images/navi7.png?raw=true",m=JSON.parse('{"title":"7 文本处理","description":"","frontmatter":{},"headers":[],"relativePath":"07/0.md","filePath":"07/0.md","lastUpdated":null}'),i={name:"07/0.md"};function n(s,a,_,d,c,h){return t(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="_7-文本处理" tabindex="-1">7 文本处理 <a class="header-anchor" href="#_7-文本处理" aria-label="Permalink to &quot;7 文本处理&quot;">​</a></h1><p>Web开发中对于文本处理是非常重要的一部分，我们往往需要对输出或者输入的内容进行处理，这里的文本包括字符串、数字、Json、XML等等。Go语言作为一门高性能的语言，对这些文本的处理都有官方的标准库来支持。而且在你使用中你会发现Go标准库的一些设计相当的巧妙，而且对于使用者来说也很方便就能处理这些文本。本章我们将通过四个小节的介绍，让用户对Go语言处理文本有一个很好的认识。</p><p>XML是目前很多标准接口的交互语言，很多时候和一些Java编写的webserver进行交互都是基于XML标准进行交互，7.1小节将介绍如何处理XML文本，我们使用XML之后发现它太复杂了，现在很多互联网企业对外的API大多数采用了JSON格式，这种格式描述简单，但是又能很好的表达意思，7.2小节我们将讲述如何来处理这样的JSON格式数据。正则是一个让人又爱又恨的工具，它处理文本的能力非常强大，我们在前面表单验证里面已经有所领略它的强大，7.3小节将详细的更深入的讲解如何利用好Go的正则。Web开发中一个很重要的部分就是MVC分离，在Go语言的Web开发中V有一个专门的包来支持<code>template</code>，7.4小节将详细的讲解如何使用模版来进行输出内容。7.5小节将详细介绍如何进行文件和文件夹的操作。7.6小节介绍了字符串的相关操作。</p><h2 id="目录" tabindex="-1">目录 <a class="header-anchor" href="#目录" aria-label="Permalink to &quot;目录&quot;">​</a></h2><p><img src="'+o+'" alt=""></p><h2 id="links" tabindex="-1">links <a class="header-anchor" href="#links" aria-label="Permalink to &quot;links&quot;">​</a></h2><ul><li><a href="/">目录</a></li><li>上一章: <a href="/06/5.html">第六章总结</a></li><li>下一节: <a href="/07/1.html">XML处理</a></li></ul>',7)])])}const u=e(i,[["render",n]]);export{m as __pageData,u as default};
